public static void main(Args _args)
{
    FormRun formRun = _args.caller();
    FormDataSource  ETG_ACFAgreementSignature_ds =  formRun.dataSource(1) as FormDataSource;
    ETG_ACFAgreementSignature agreementSign = ETG_ACFAgreementSignature_ds.cursor() as ETG_ACFAgreementSignature;

    ttsbegin;
    agreementSign.selectForUpdate(true);
    agreementSign.ETGSignature = conNull();
    agreementSign.update();
    ttscommit;
